class Solution {
public:
    vector<int> earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
        int earliest = (firstPlayer + secondPlayer - 2) / (n / 2);
        int latest = n - (firstPlayer > n / 2 ? n - firstPlayer : firstPlayer - 1) - (secondPlayer > n / 2 ? n - secondPlayer : secondPlayer - 1);
        return {earliest, latest};
    }
};
